  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 5, $hb$Best Pet Synergies For Ruby (NEW)$hb$, $hb$With the new war pet system in Call of Dragons it’s aso important to pair Ruby with the right pet to gain more synergies. Please also check out the full tier list of all war pets in Call of Dragons here to see which ones are worth the invest in general.$hb$, '{}'::text[], $hb$https://www.allclash.com/best-ruby-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 6, $hb$Best Builds For Ruby$hb$, $hb$Below you will find the talent tree builds for Ruby that make sense when running as the primary commander in any legion in Call of Dragons. Please also refer to the description below each talent tree as I explain a general route on how you should spend your talents there + some additional background for each talent build that I very likely will appreciate. This is the talent tree setup that makes most sense with her. I have seen the most ridiculous ones, like 40% March Speed Built or weird Precision Tree setups so be aware that some content creators create those just to create, not because it makes sense (I really don’t like calling someone out and rather focus on my work here but if I see ridiculous content being spun that just might set up player wrong I need to say something). So, bottom line, don’t over-complicate her straightforward kit and leverage her strength with a marksman tree build and you will see how the new generation of heroes does, they do truly amazing.$hb$, array[$hb$https://www.allclash.com/wp-content/uploads/2025/12/ruby-talent-tree-build.jpg$hb$]::text[], $hb$https://www.allclash.com/best-ruby-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb$, false);
